import { computed, inject } from '@angular/core';
import { signalStore, withState, withMethods, withComputed, patchState } from '@ngrx/signals';
import { rxMethod } from '@ngrx/signals/rxjs-interop';
import { pipe, switchMap, tap, map, catchError, of } from 'rxjs';
import { BatchJob, BatchJobStatus } from '../models/models';
import { BatchService } from '../services/batch.service';
import { NotificationService } from '../services/notification.service';

export interface JobsState {
  jobs: BatchJob[];
  activeJobId: string | null;
  isLoading: boolean;
  error: string | null;
  filterStatus: BatchJobStatus | 'ALL';
  pageIndex: number; // for hypothetical pagination
  pageSize: number;
}

const initialState: JobsState = {
  jobs: [],
  activeJobId: null,
  isLoading: false,
  error: null,
  filterStatus: 'ALL',
  pageIndex: 0,
  pageSize: 100,
};

export const JobsStore = signalStore(
  { providedIn: 'root' },
  withState(initialState),
  withComputed((store) => ({
    filteredJobs: computed(() => {
      const jobs = store.jobs();
      const status = store.filterStatus();
      return status === 'ALL' ? jobs : jobs.filter((job) => job.status === status);
    }),
    activeJob: computed(() => {
      const id = store.activeJobId();
      return store.jobs().find((job) => job.id === id) || null;
    }),
    totalJobs: computed(() => store.jobs().length),
  })),
  withMethods((store, batchService = inject(BatchService), notificationService = inject(NotificationService)) => ({
    setFilter(status: BatchJobStatus | 'ALL') {
      patchState(store, { filterStatus: status });
    },
    setActiveJob(id: string | null) {
      patchState(store, { activeJobId: id });
    },
    addJob(job: BatchJob) {
      patchState(store, { jobs: [job, ...store.jobs()] });
    },
    loadJobs: rxMethod<void>(
      pipe(
        tap(() => patchState(store, { isLoading: true, error: null })),
        switchMap(() => {
          return batchService.loadJobs().pipe(
            tap((jobs) => patchState(store, { jobs, isLoading: false })),
            catchError((err) => {
              const errorMsg = err.message || 'Failed to load jobs';
              patchState(store, { error: errorMsg, isLoading: false });
              notificationService.error(errorMsg);
              return of([]);
            })
          );
        })
      )
    ),
  }))
);

import { Injectable, signal } from '@angular/core';

export interface Notification {
  id: string;
  type: 'success' | 'error' | 'info';
  message: string;
}

/**
 * Service for managing toast notifications.
 */
@Injectable({
  providedIn: 'root'
})
export class NotificationService {
  private notificationsSignal = signal<Notification[]>([]);

  /** Current notifications */
  readonly notifications = this.notificationsSignal.asReadonly();

  /**
   * Show a success notification.
   * @param message The message to display
   */
  success(message: string): void {
    this.addNotification('success', message);
  }

  /**
   * Show an error notification.
   * @param message The message to display
   */
  error(message: string): void {
    this.addNotification('error', message);
  }

  /**
   * Show an info notification.
   * @param message The message to display
   */
  info(message: string): void {
    this.addNotification('info', message);
  }

  /**
   * Remove a notification by ID.
   * @param id The notification ID
   */
  remove(id: string): void {
    this.notificationsSignal.update(notifications => 
      notifications.filter(n => n.id !== id)
    );
  }

  private addNotification(type: 'success' | 'error' | 'info', message: string): void {
    const id = Math.random().toString(36).substring(2, 9);
    this.notificationsSignal.update(notifications => [
      ...notifications,
      { id, type, message }
    ]);

    // Auto-remove after 5 seconds
    setTimeout(() => {
      this.remove(id);
    }, 5000);
  }
}

import { Injectable, inject, signal } from '@angular/core';
import { ApiService } from './api.service';
import { Observable } from 'rxjs';
import { tap } from 'rxjs/operators';

export interface OpResult {
  output: string;
  diff?: string;
  modifiedFiles?: string[];
}

/**
 * Service for local audit and fix operations.
 */
@Injectable({
  providedIn: 'root'
})
export class LocalOpService {
  private api = inject(ApiService);

  private isOperatingSignal = signal<boolean>(false);
  private lastResultSignal = signal<OpResult | null>(null);

  /** Whether an operation is in progress */
  readonly isOperating = this.isOperatingSignal.asReadonly();
  /** Result of the last operation */
  readonly lastResult = this.lastResultSignal.asReadonly();

  /**
   * Executes an audit operation.
   * @param pattern Regex pattern to audit
   * @param tools Selected tools
   * @param args Tool arguments
   */
  audit(pattern: string, tools: string[], args: any): Observable<OpResult> {
    this.isOperatingSignal.set(true);
    return this.api.post<OpResult>('/local/audit', { pattern, tools, args }).pipe(
      tap({
        next: (res) => {
          this.lastResultSignal.set(res);
          this.isOperatingSignal.set(false);
        },
        error: () => this.isOperatingSignal.set(false)
      })
    );
  }

  /**
   * Executes a fix operation.
   * @param pattern Regex pattern to fix
   * @param tools Selected tools
   * @param args Tool arguments
   * @param dryRun Whether to perform a dry run
   */
  fix(pattern: string, tools: string[], args: any, dryRun: boolean): Observable<OpResult> {
    this.isOperatingSignal.set(true);
    return this.api.post<OpResult>('/local/fix', { pattern, tools, args, dryRun }).pipe(
      tap({
        next: (res) => {
          this.lastResultSignal.set(res);
          this.isOperatingSignal.set(false);
        },
        error: () => this.isOperatingSignal.set(false)
      })
    );
  }

  /**
   * Clears the last result.
   */
  clearResult(): void {
    this.lastResultSignal.set(null);
  }
}

