import { Injectable, inject } from '@angular/core';
import { HttpClient, HttpErrorResponse } from '@angular/common/http';
import { Observable, throwError } from 'rxjs';
import { catchError, retry } from 'rxjs/operators';

/**
 * Generic API Service for making HTTP requests.
 */
@Injectable({
  providedIn: 'root'
})
export class ApiService {
  private http = inject(HttpClient);

  /** Base API URL */
  private baseUrl = '/api';

  /**
   * Performs a GET request.
   * @param path The API endpoint path
   * @returns Observable of the response
   */
  get<T>(path: string): Observable<T> {
    return this.http.get<T>(`${this.baseUrl}${path}`).pipe(
      retry(2),
      catchError(this.handleError)
    );
  }

  /**
   * Performs a POST request.
   * @param path The API endpoint path
   * @param body The request body payload
   * @returns Observable of the response
   */
  post<T>(path: string, body: any = {}): Observable<T> {
    return this.http.post<T>(`${this.baseUrl}${path}`, body).pipe(
      catchError(this.handleError)
    );
  }

  /**
   * Performs a PUT request.
   * @param path The API endpoint path
   * @param body The request body payload
   * @returns Observable of the response
   */
  put<T>(path: string, body: any = {}): Observable<T> {
    return this.http.put<T>(`${this.baseUrl}${path}`, body).pipe(
      catchError(this.handleError)
    );
  }

  /**
   * Performs a DELETE request.
   * @param path The API endpoint path
   * @returns Observable of the response
   */
  delete<T>(path: string): Observable<T> {
    return this.http.delete<T>(`${this.baseUrl}${path}`).pipe(
      catchError(this.handleError)
    );
  }

  /**
   * Standardized error handler for HTTP requests.
   * @param error The HTTP error response
   * @returns An observable throwing a user-facing error message
   */
  private handleError(error: HttpErrorResponse): Observable<never> {
    let errorMessage = 'An unknown error occurred!';
    if (error.error instanceof ErrorEvent) {
      // Client-side or network error
      errorMessage = `Error: ${error.error.message}`;
    } else {
      // Backend error
      errorMessage = `Error Code: ${error.status}\nMessage: ${error.message}`;
    }
    return throwError(() => new Error(errorMessage));
  }
}

import { Injectable, inject, signal } from '@angular/core';
import { ApiService } from './api.service';
import { BatchJob } from '../models/models';
import { tap } from 'rxjs/operators';
import { Observable } from 'rxjs';

/**
 * Service for managing batch jobs.
 */
@Injectable({
  providedIn: 'root'
})
export class BatchService {
  private api = inject(ApiService);

  private jobsSignal = signal<BatchJob[]>([]);
  private activeJobSignal = signal<BatchJob | null>(null);

  /** List of all batch jobs */
  readonly jobs = this.jobsSignal.asReadonly();
  /** The currently viewed job */
  readonly activeJob = this.activeJobSignal.asReadonly();

  /**
   * Loads all batch jobs.
   */
  loadJobs(): Observable<BatchJob[]> {
    return this.api.get<BatchJob[]>('/batch/jobs').pipe(
      tap(jobs => this.jobsSignal.set(jobs))
    );
  }

  /**
   * Loads details for a specific job.
   * @param id Job ID
   */
  loadJob(id: string): Observable<BatchJob> {
    return this.api.get<BatchJob>(`/batch/jobs/${id}`).pipe(
      tap(job => this.activeJobSignal.set(job))
    );
  }

  /**
   * Creates a new batch fix job.
   * @param target Target organization or repo
   * @param title Title of the issue/PR
   * @param description Description of the issue/PR
   * @param pattern Regex pattern to match
   * @param tools Tools to run
   * @param args Arguments for the tools
   * @param safety_mode Whether to use safety mode
   * @param max_repos Maximum number of repositories to process
   * @param max_prs_per_hour Maximum number of PRs per hour
   */
  createBatchFix(target: string, title: string, description: string, pattern: string, tools: string[], args: any, safety_mode: boolean = true, max_repos?: number, max_prs_per_hour?: number): Observable<BatchJob> {
    return this.api.post<BatchJob>('/batch/fix', { org: target, issue: title, description, pattern, tools, tool_args: args, safety_mode, max_repos, max_prs_per_hour }).pipe(
      tap(job => this.jobsSignal.update(jobs => [job, ...jobs]))
    );
  }

  /**
   * Runs a pipeline from config.
   * @param config Pipeline configuration string
   * @param safety_mode Whether to use safety mode
   * @param max_repos Maximum number of repositories to process
   * @param max_prs_per_hour Maximum number of PRs per hour
   */
  runPipeline(config: string, safety_mode: boolean = true, max_repos?: number, max_prs_per_hour?: number): Observable<BatchJob> {
    return this.api.post<BatchJob>('/batch/run', { config_path: config, safety_mode, max_repos, max_prs_per_hour }).pipe(
      tap(job => this.jobsSignal.update(jobs => [job, ...jobs]))
    );
  }

  /**
   * Resumes an interrupted job.
   * @param id Job ID
   */
  resumeJob(id: string): Observable<BatchJob> {
    return this.api.post<BatchJob>(`/batch/jobs/${id}/resume`).pipe(
      tap(job => {
        this.activeJobSignal.set(job);
        this.jobsSignal.update(jobs => jobs.map(j => j.id === id ? job : j));
      })
    );
  }

  /**
   * Clears the currently active job.
   */
  clearActiveJob(): void {
    this.activeJobSignal.set(null);
  }
}

import { Injectable, inject, signal } from '@angular/core';
import { ApiService } from './api.service';
import { Observable } from 'rxjs';
import { tap } from 'rxjs/operators';

export interface OpResult {
  output: string;
  diff?: string;
  modifiedFiles?: string[];
}

/**
 * Service for local audit and fix operations.
 */
@Injectable({
  providedIn: 'root'
})
export class LocalOpService {
  private api = inject(ApiService);

  private isOperatingSignal = signal<boolean>(false);
  private lastResultSignal = signal<OpResult | null>(null);

  /** Whether an operation is in progress */
  readonly isOperating = this.isOperatingSignal.asReadonly();
  /** Result of the last operation */
  readonly lastResult = this.lastResultSignal.asReadonly();

  /**
   * Executes an audit operation.
   * @param pattern Regex pattern to audit
   * @param tools Selected tools
   * @param args Tool arguments
   */
  audit(pattern: string, tools: string[], args: any): Observable<OpResult> {
    this.isOperatingSignal.set(true);
    return this.api.post<OpResult>('/local/audit', { pattern, tools, args }).pipe(
      tap({
        next: (res) => {
          this.lastResultSignal.set(res);
          this.isOperatingSignal.set(false);
        },
        error: () => this.isOperatingSignal.set(false)
      })
    );
  }

  /**
   * Executes a fix operation.
   * @param pattern Regex pattern to fix
   * @param tools Selected tools
   * @param args Tool arguments
   * @param dryRun Whether to perform a dry run
   */
  fix(pattern: string, tools: string[], args: any, dryRun: boolean): Observable<OpResult> {
    this.isOperatingSignal.set(true);
    return this.api.post<OpResult>('/local/fix', { pattern, tools, args, dryRun }).pipe(
      tap({
        next: (res) => {
          this.lastResultSignal.set(res);
          this.isOperatingSignal.set(false);
        },
        error: () => this.isOperatingSignal.set(false)
      })
    );
  }

  /**
   * Clears the last result.
   */
  clearResult(): void {
    this.lastResultSignal.set(null);
  }
}

import { Injectable, signal } from '@angular/core';

export interface Notification {
  id: string;
  type: 'success' | 'error' | 'info';
  message: string;
}

/**
 * Service for managing toast notifications.
 */
@Injectable({
  providedIn: 'root'
})
export class NotificationService {
  private notificationsSignal = signal<Notification[]>([]);

  /** Current notifications */
  readonly notifications = this.notificationsSignal.asReadonly();

  /**
   * Show a success notification.
   * @param message The message to display
   */
  success(message: string): void {
    this.addNotification('success', message);
  }

  /**
   * Show an error notification.
   * @param message The message to display
   */
  error(message: string): void {
    this.addNotification('error', message);
  }

  /**
   * Show an info notification.
   * @param message The message to display
   */
  info(message: string): void {
    this.addNotification('info', message);
  }

  /**
   * Remove a notification by ID.
   * @param id The notification ID
   */
  remove(id: string): void {
    this.notificationsSignal.update(notifications => 
      notifications.filter(n => n.id !== id)
    );
  }

  private addNotification(type: 'success' | 'error' | 'info', message: string): void {
    const id = Math.random().toString(36).substring(2, 9);
    this.notificationsSignal.update(notifications => [
      ...notifications,
      { id, type, message }
    ]);

    // Auto-remove after 5 seconds
    setTimeout(() => {
      this.remove(id);
    }, 5000);
  }
}

import { Injectable, inject, signal } from '@angular/core';
import { ApiService } from './api.service';
import { Organization, Repository } from '../models/models';
import { tap } from 'rxjs/operators';
import { Observable } from 'rxjs';

/**
 * Service for managing organizations and repositories.
 */
@Injectable({
  providedIn: 'root'
})
export class OrgService {
  private api = inject(ApiService);

  private orgsSignal = signal<Organization[]>([]);
  private reposSignal = signal<Repository[]>([]);
  private isLoadingSignal = signal<boolean>(false);

  /** List of organizations */
  readonly orgs = this.orgsSignal.asReadonly();
  /** List of repositories for the selected org */
  readonly repos = this.reposSignal.asReadonly();
  /** Loading state */
  readonly isLoading = this.isLoadingSignal.asReadonly();

  /**
   * Fetches all ingested organizations.
   */
  loadOrgs(): Observable<Organization[]> {
    this.isLoadingSignal.set(true);
    return this.api.get<Organization[]>('/orgs').pipe(
      tap({
        next: (orgs) => {
          this.orgsSignal.set(orgs);
          this.isLoadingSignal.set(false);
        },
        error: () => this.isLoadingSignal.set(false)
      })
    );
  }

  /**
   * Ingests a new organization.
   * @param name Org name
   * @param provider Provider
   * @param dbUrl Database URL
   */
  ingestOrg(name: string, provider: string, dbUrl: string): Observable<Organization> {
    this.isLoadingSignal.set(true);
    return this.api.post<Organization>('/orgs/ingest', { name, provider, dbUrl }).pipe(
      tap({
        next: (org) => {
          this.orgsSignal.update(orgs => [...orgs, org]);
          this.isLoadingSignal.set(false);
        },
        error: () => this.isLoadingSignal.set(false)
      })
    );
  }

  /**
   * Loads repositories for an organization.
   * @param orgId Organization ID
   */
  loadRepos(orgId: string): Observable<Repository[]> {
    this.isLoadingSignal.set(true);
    return this.api.get<Repository[]>(`/orgs/${orgId}/repos`).pipe(
      tap({
        next: (repos) => {
          this.reposSignal.set(repos);
          this.isLoadingSignal.set(false);
        },
        error: () => this.isLoadingSignal.set(false)
      })
    );
  }
}

import { Injectable, inject, signal } from '@angular/core';
import { ApiService } from './api.service';
import { PullRequest } from '../models/models';
import { tap } from 'rxjs/operators';
import { Observable } from 'rxjs';

/**
 * Service for managing pull requests and sync operations.
 */
@Injectable({
  providedIn: 'root'
})
export class PrService {
  private api = inject(ApiService);

  private prsSignal = signal<PullRequest[]>([]);
  private isSyncingSignal = signal<boolean>(false);

  /** List of PRs */
  readonly prs = this.prsSignal.asReadonly();
  /** Whether a sync operation is in progress */
  readonly isSyncing = this.isSyncingSignal.asReadonly();

  /**
   * Loads PRs for an organization.
   * @param orgId Organization ID
   */
  loadPrs(orgId: string): Observable<PullRequest[]> {
    return this.api.get<PullRequest[]>(`/prs?orgId=${orgId}`).pipe(
      tap(prs => this.prsSignal.set(prs))
    );
  }

  /**
   * Syncs local PRs to upstream.
   * @param orgId Target organization
   * @param maxRate Maximum PRs to sync
   */
  syncPrs(orgId: string, maxRate: number): Observable<{ syncedCount: number }> {
    this.isSyncingSignal.set(true);
    return this.api.post<{ syncedCount: number }>('/prs/sync', { orgId, maxRate }).pipe(
      tap({
        next: () => this.isSyncingSignal.set(false),
        error: () => this.isSyncingSignal.set(false)
      })
    );
  }
}

import { Injectable, inject, signal } from '@angular/core';
import { ApiService } from './api.service';
import { SystemHealth } from '../models/models';
import { tap } from 'rxjs/operators';

/**
 * Service for managing system health state.
 */
@Injectable({
  providedIn: 'root'
})
export class SystemStateService {
  private api = inject(ApiService);

  private healthSignal = signal<SystemHealth>({ rest: 'DOWN', rpc: 'DOWN', agent: 'DOWN' });
  private isLoadingSignal = signal<boolean>(false);

  /** Current health state */
  readonly health = this.healthSignal.asReadonly();
  /** Whether a check is currently in progress */
  readonly isLoading = this.isLoadingSignal.asReadonly();

  /**
   * Fetches the current system health.
   */
  checkHealth() {
    this.isLoadingSignal.set(true);
    return this.api.get<SystemHealth>('/health').pipe(
      tap({
        next: (health) => {
          this.healthSignal.set(health);
          this.isLoadingSignal.set(false);
        },
        error: () => {
          this.healthSignal.set({ rest: 'DOWN', rpc: 'DOWN', agent: 'DOWN' });
          this.isLoadingSignal.set(false);
        }
      })
    );
  }
}

