@if (label()) {
  <label class="input-label" [for]="inputId()">{{ label() }}</label>
}

@if (type() === 'textarea') {
  <textarea
    class="form-control"
    [id]="inputId()"
    [placeholder]="placeholder()"
    [disabled]="isDisabled"
    [value]="value"
    (input)="onInputChange($event)"
    (blur)="onTouched()"
    rows="3"
  ></textarea>
} @else if (type() === 'select') {
  <select
    class="form-select"
    [id]="inputId()"
    [disabled]="isDisabled"
    [value]="value"
    (change)="onSelectChange($event)"
    (blur)="onTouched()"
  >
    @for (option of options(); track option.value) {
      <option [value]="option.value">{{ option.label }}</option>
    }
  </select>
} @else {
  <input
    class="form-control"
    [type]="type()"
    [id]="inputId()"
    [placeholder]="placeholder()"
    [disabled]="isDisabled"
    [value]="value"
    (input)="onInputChange($event)"
    (blur)="onTouched()"
  />
}

