signalStore(
  { providedIn: 'root' },
  withState(initialState),
  withComputed((store) => ({
    filteredJobs: computed(() => {
      const jobs = store.jobs();
      const status = store.filterStatus();
      return status === 'ALL' ? jobs : jobs.filter((job) => job.status === status);
    }),
    activeJob: computed(() => {
      const id = store.activeJobId();
      return store.jobs().find((job) => job.id === id) || null;
    }),
    totalJobs: computed(() => store.jobs().length),
  })),
  withMethods((store, batchService = inject(BatchService), notificationService = inject(NotificationService)) => ({
    setFilter(status: BatchJobStatus | 'ALL') {
      patchState(store, { filterStatus: status });
    },
    setActiveJob(id: string | null) {
      patchState(store, { activeJobId: id });
    },
    addJob(job: BatchJob) {
      patchState(store, { jobs: [job, ...store.jobs()] });
    },
    loadJobs: rxMethod<void>(
      pipe(
        tap(() => patchState(store, { isLoading: true, error: null })),
        switchMap(() => {
          return batchService.loadJobs().pipe(
            tap((jobs) => patchState(store, { jobs, isLoading: false })),
            catchError((err) => {
              const errorMsg = err.message || 'Failed to load jobs';
              patchState(store, { error: errorMsg, isLoading: false });
              notificationService.error(errorMsg);
              return of([]);
            })
          );
        })
      )
    ),
  }))
)

signalStore(
  { providedIn: 'root' },
  withState(initialState),
  withComputed((store) => ({
    totalPrs: computed(() => store.prs().length),
    syncedPrs: computed(() => store.prs().filter(pr => pr.status === 'SYNCED')),
    localPrs: computed(() => store.prs().filter(pr => pr.status === 'LOCAL')),
    conflictPrs: computed(() => store.prs().filter(pr => pr.status === 'CONFLICT')),
  })),
  withMethods((store, prService = inject(PrService), notificationService = inject(NotificationService)) => {
    // Define loadPrs internally first so we can use it within other methods
    const loadPrsFn = rxMethod<string>(
      pipe(
        tap((orgId) => patchState(store, { isLoading: true, error: null, activeOrgId: orgId })),
        switchMap((orgId) => {
          return prService.loadPrs(orgId).pipe(
            tap((prs) => patchState(store, { prs, isLoading: false })),
            catchError((err) => {
              const errorMsg = err.message || 'Failed to load PRs';
              patchState(store, { error: errorMsg, isLoading: false });
              notificationService.error(errorMsg);
              return of([]);
            })
          );
        })
      )
    );

    return {
      loadPrs: loadPrsFn,
      syncPrs: rxMethod<{ orgId: string; maxRate: number }>(
        pipe(
          tap(() => patchState(store, { isSyncing: true })),
          switchMap(({ orgId, maxRate }) => {
            return prService.syncPrs(orgId, maxRate).pipe(
              tap(({ syncedCount }) => {
                patchState(store, { isSyncing: false });
                notificationService.success(`Successfully synced ${syncedCount} PRs.`);
                // Reload PRs after successful sync
                if (store.activeOrgId() === orgId) {
                  loadPrsFn(orgId);
                }
              }),
              catchError((err) => {
                patchState(store, { isSyncing: false });
                notificationService.error(err.message || 'Failed to sync PRs');
                return of(null);
              })
            );
          })
        )
      )
    };
  })
)

